#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAXN 60000
#define MAXQ 250000
#define MAXS 1000000000000000000LL

int compare(const void *a, const void *b) {
    return (*(long long *)a - *(long long *)b);
}

long long cross_product(long long x1, long long y1, long long x2, long long y2) {
    return x1 * y2 - x2 * y1;
}

long long triangle_area(long long x1, long long y1, long long x2, long long y2, long long x3, long long y3) {
    return abs(cross_product(x2 - x1, y2 - y1, x3 - x1, y3 - y1)) / 2;
}

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    long long X[MAXN], Y[MAXN];
    for (int i = 0; i < N; i++) {
        scanf("%lld %lld", &X[i], &Y[i]);
    }
    for (int i = 0; i < Q; i++) {
        int B, C;
        long long S;
        scanf("%d %d %lld", &B, &C, &S);
        B--;
        C--;
        int count = 0;
        for (int j = 0; j < N; j++) {
            if (j == B || j == C) continue;
            long long area = triangle_area(X[B], Y[B], X[C], Y[C], X[j], Y[j]);
            if (area >= S) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

