import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        long[] X = new long[N];
        long[] Y = new long[N];
        for (int i = 0; i < N; i++) {
            X[i] = sc.nextLong();
            Y[i] = sc.nextLong();
        }
        for (int i = 0; i < Q; i++) {
            int B = sc.nextInt() - 1;
            int C = sc.nextInt() - 1;
            long S = sc.nextLong();
            int count = 0;
            for (int j = 0; j < N; j++) {
                if (j == B || j == C) continue;
                long area = triangleArea(X[B], Y[B], X[C], Y[C], X[j], Y[j]);
                if (area >= S) count++;
            }
            System.out.println(count);
        }
    }

    public static long triangleArea(long x1, long y1, long x2, long y2, long x3, long y3) {
        return Math.abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1)) / 2;
    }
}

